(function(){function getComponentsArray(component){let cleanedComp=component.trim().substr(2,component.length-4);return cleanedComp.split('|')}
    const componentToHtmlTable=components=>{let table=['<table class="image-accessory"><tr>'];const component=getComponentsArray(components);table.push('<td>'+component[0]+'</td>');table.push('<td>'+component[1]+'</td>');table.push('</tr></table>');return table.join('')};const before=content=>{let imageStamps=content.match(/<:.*?:>/g);if(!imageStamps)return content;let tableComponent;for(let i=0;i<imageStamps.length;i++){tableComponent=componentToHtmlTable(imageStamps[i]);content=content.replace(imageStamps[i],tableComponent)}
        console.log(content);return content};const imageParser=hook=>{hook.beforeEach(content=>before(content))};$docsify.plugins=[].concat(imageParser,$docsify.plugins)}())